const cellKey = ([x, y]: Cell): string => `${x},${y}`;

const survives = (isAlive: boolean, neighborCount: number): boolean =>
  (isAlive && neighborCount === 2) || neighborCount === 3;

export function nextGeneration(cells: readonly Cell[]): Cell[] {
  const aliveKeys = new Set(cells.map(cellKey));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const key = cellKey(neighbor);
      const existing = neighborCounts.get(key);
      if (existing) {
        existing.count++;
      } else {
        neighborCounts.set(key, { cell: neighbor, count: 1 });
      }
    }
  }

  const result: Cell[] = [];
  for (const [key, { cell, count }] of neighborCounts) {
    if (survives(aliveKeys.has(key), count)) {
      result.push(cell);
    }
  }
  return result;
}
